"""
TDD Stage: full_normalize
Full 3-pass layer norm: Pass 1 mean, Pass 2 variance+rsqrt, Pass 3 normalize with gamma/beta. Tests with and without gamma/beta.
"""

import pytest
import torch
import ttnn

from ttnn.operations.layer_norm_rm import layer_norm_rm


def pytorch_reference(input_tensor, gamma=None, beta=None):
    """PyTorch reference for this stage."""
    x = input_tensor
    weight = gamma.squeeze(0).squeeze(0).squeeze(0) if gamma is not None else None
    bias = beta.squeeze(0).squeeze(0).squeeze(0) if beta is not None else None
    return torch.nn.functional.layer_norm(x, [x.shape[-1]], weight=weight, bias=bias, eps=1e-5)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_full_normalize(device, shape):
    """Verify full layer normalization (no gamma/beta)."""
    layout = ttnn.ROW_MAJOR_LAYOUT
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=layout,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm_rm(ttnn_input)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
